    49→			t.Errorf("expected field 'does_not_exist', got %q", errs[0].Field)
    50→		}
    51→		if errs[0].Message != "unknown field" {
    52→			t.Errorf("unexpected message: %q", errs[0].Message)
    53→		}
    54→	})
    55→
    56→	t.Run("bad enum value for state", func(t *testing.T) {
    57→		req := search.SearchRequest{
    58→			Filters: []search.FilterInput{
    59→				{Field: "state", Value: mustJSON(search.MultiEnumFilter{Values: []string{"XX"}})},
    60→			},
    61→		}
    62→		errs := search.ValidateRequest(reg, req, true)
    63→		if len(errs) != 1 {
    64→			t.Fatalf("expected 1 error, got %d", len(errs))
    65→		}
    66→		if !strings.Contains(errs[0].Message, "not in allowed options") {
    67→			t.Errorf("unexpected message: %q", errs[0].Message)
    68→		}
    69→	})
    70→
    71→	t.Run("multi enum bad value", func(t *testing.T) {
    72→		req := search.SearchRequest{
    73→			Filters: []search.FilterInput{
    74→				{Field: "application_platforms", Value: mustJSON(search.MultiEnumFilter{Values: []string{"Not A Real App"}})},
    75→			},
    76→		}
